export enum UserRole {
  ADMIN = 'admin',
  STAFF = 'staff',
  CUSTOMER = 'customer'
}

export type PricingType = 'kg' | 'unit';

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  pricingType: PricingType;
  stock: number;
  image: string;
  description: string;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface UserProfile {
  id: string;
  fullName: string;
  email: string;
  phone: string;
  role: UserRole;
  nif?: string;
  address?: string;
}

export interface Order {
  id: string;
  customerId: string;
  customerName: string;
  items: CartItem[];
  total: number;
  tax: number;
  status: 'pending' | 'received' | 'ready' | 'delivered';
  type: 'pos' | 'online';
  createdAt: string;
  invoiceId?: string;
}

export interface Invoice {
  id: string;
  orderId: string;
  sequence: string; // e.g., FT 2024/0001
  nif: string;
  hash: string;
  taxStamp: string;
  createdAt: string;
}

export interface AppState {
  currentUser: UserProfile | null;
  products: Product[];
  orders: Order[];
  invoices: Invoice[];
}

import { UserRole } from '../types';

/**
 * Masks sensitive information like emails or phone numbers
 * if the user role is not authorized (Staff can only see masked data).
 */
export const maskPII = (value: string, role: UserRole): string => {
  if (role === UserRole.ADMIN) return value;

  // Phone masking: 923***123
  if (/^\d{9,12}$/.test(value.replace(/\D/g, ''))) {
    return value.slice(0, 3) + '***' + value.slice(-3);
  }

  // Email masking: a***@domain.com
  if (value.includes('@')) {
    const [name, domain] = value.split('@');
    return name[0] + '***@' + domain;
  }

  return '***';
};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getMarketInsights = async (salesData: any) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `As a business analyst for a high-end fish market, analyze this sales data and provide 3 actionable insights for inventory and pricing strategy: ${JSON.stringify(salesData)}. Return response in Markdown.`,
      config: {
        systemInstruction: "You are a professional retail and seafood market consultant. Keep advice practical and concise.",
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Insight Error:", error);
    return "Unable to generate insights at this time.";
  }
};

import React, { useState, useMemo } from 'react';
import { HashRouter, Routes, Route, Navigate, Link, useLocation } from 'react-router-dom';
import { UserRole, UserProfile, Product, Order, Invoice, CartItem } from './types';
import { MOCK_PRODUCTS, ICONS, COLORS } from './constants';
import POSView from './components/POSView';
import CatalogView from './components/CatalogView';
import AdminDashboard from './components/AdminDashboard';
import ProfileView from './components/ProfileView';
import OrderTracking from './components/OrderTracking';
import AGTReports from './components/AGTReports';

// Mock Auth Context simulated via simple state
const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>({
    id: 'usr-1',
    fullName: 'Artur Gonçalves',
    email: 'artur@fishmarket.ao',
    phone: '923000111',
    role: UserRole.ADMIN, // Default to Admin for full demo access
    nif: '5401234567'
  });

  const [products] = useState<Product[]>(MOCK_PRODUCTS);
  const [orders, setOrders] = useState<Order[]>([]);
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);

  const handleRoleChange = (role: UserRole) => {
    setCurrentUser(prev => prev ? { ...prev, role } : null);
  };

  const addToCart = (product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      return [...prev, { ...product, quantity }];
    });
  };

  const createOrder = (type: 'pos' | 'online', customNif?: string) => {
    const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const tax = total * 0.14; // 14% IVA
    const orderId = `ORD-${Date.now()}`;
    const invoiceId = `INV-${Date.now()}`;

    const newOrder: Order = {
      id: orderId,
      customerId: currentUser?.id || 'guest',
      customerName: currentUser?.fullName || 'Guest Customer',
      items: [...cart],
      total: total + tax,
      tax,
      status: 'pending',
      type,
      createdAt: new Date().toISOString(),
      invoiceId
    };

    const newInvoice: Invoice = {
      id: invoiceId,
      orderId,
      sequence: `FT ${new Date().getFullYear()}/${(invoices.length + 1).toString().padStart(4, '0')}`,
      nif: customNif || currentUser?.nif || '999999999',
      hash: Math.random().toString(36).substring(7).toUpperCase(),
      taxStamp: 'AGT-CERT-2024-' + Math.random().toString(36).substring(4).toUpperCase(),
      createdAt: new Date().toISOString()
    };

    setOrders([newOrder, ...orders]);
    setInvoices([newInvoice, ...invoices]);
    setCart([]);
    alert(`Success! Invoice ${newInvoice.sequence} generated.`);
  };

  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col md:flex-row bg-slate-50 text-slate-900">
        {/* Role Switcher Demo Tool */}
        <div className="fixed bottom-4 right-4 z-50 flex gap-2 bg-white p-2 rounded-full shadow-2xl border border-blue-100">
          <button onClick={() => handleRoleChange(UserRole.ADMIN)} className={`px-3 py-1 rounded-full text-xs font-bold ${currentUser?.role === UserRole.ADMIN ? 'bg-blue-800 text-white' : 'hover:bg-blue-50'}`}>Admin</button>
          <button onClick={() => handleRoleChange(UserRole.STAFF)} className={`px-3 py-1 rounded-full text-xs font-bold ${currentUser?.role === UserRole.STAFF ? 'bg-blue-800 text-white' : 'hover:bg-blue-50'}`}>Staff</button>
          <button onClick={() => handleRoleChange(UserRole.CUSTOMER)} className={`px-3 py-1 rounded-full text-xs font-bold ${currentUser?.role === UserRole.CUSTOMER ? 'bg-blue-800 text-white' : 'hover:bg-blue-50'}`}>Customer</button>
        </div>

        {/* Sidebar Navigation */}
        <Sidebar role={currentUser?.role || UserRole.CUSTOMER} />

        {/* Main Content Area */}
        <main className="flex-1 overflow-y-auto pb-20 md:pb-0">
          <div className="max-w-7xl mx-auto p-4 md:p-8">
            <Routes>
              {/* Common Routes */}
              <Route path="/profile" element={<ProfileView user={currentUser} onSave={(u) => setCurrentUser(u)} />} />

              {/* Role Restricted Routes */}
              {currentUser?.role === UserRole.ADMIN && (
                <>
                  <Route path="/dashboard" element={<AdminDashboard orders={orders} products={products} />} />
                  <Route path="/reports" element={<AGTReports invoices={invoices} orders={orders} />} />
                </>
              )}

              {(currentUser?.role === UserRole.ADMIN || currentUser?.role === UserRole.STAFF) && (
                <Route path="/pos" element={<POSView products={products} cart={cart} addToCart={addToCart} checkout={(nif) => createOrder('pos', nif)} clearCart={() => setCart([])} role={currentUser.role} />} />
              )}

              {currentUser?.role === UserRole.CUSTOMER && (
                <>
                  <Route path="/catalog" element={<CatalogView products={products} cart={cart} addToCart={addToCart} />} />
                  <Route path="/checkout" element={<OrderTracking cart={cart} createOrder={(nif) => createOrder('online', nif)} />} />
                </>
              )}

              {/* Redirects */}
              <Route path="/" element={<Navigate to={currentUser?.role === UserRole.CUSTOMER ? "/catalog" : (currentUser?.role === UserRole.ADMIN ? "/dashboard" : "/pos")} />} />
            </Routes>
          </div>
        </main>
      </div>
    </HashRouter>
  );
};

const Sidebar: React.FC<{ role: UserRole }> = ({ role }) => {
  const location = useLocation();

  const navItems = [
    { label: 'Dashboard', path: '/dashboard', roles: [UserRole.ADMIN], icon: ICONS.Layout },
    { label: 'POS System', path: '/pos', roles: [UserRole.ADMIN, UserRole.STAFF], icon: ICONS.Cart },
    { label: 'AGT Reports', path: '/reports', roles: [UserRole.ADMIN], icon: ICONS.FileText },
    { label: 'Market Catalog', path: '/catalog', roles: [UserRole.CUSTOMER], icon: ICONS.Cart },
    { label: 'Checkout', path: '/checkout', roles: [UserRole.CUSTOMER], icon: ICONS.Search },
    { label: 'Profile', path: '/profile', roles: [UserRole.ADMIN, UserRole.STAFF, UserRole.CUSTOMER], icon: ICONS.User },
  ];

  return (
    <aside className="w-full md:w-64 bg-slate-900 text-white flex md:flex-col shadow-xl z-30 sticky top-0 md:h-screen">
      <div className="p-6 hidden md:block border-b border-slate-800">
        <h1 className="text-xl font-bold tracking-tight text-blue-400">FISH MARKET PRO</h1>
        <p className="text-[10px] text-slate-400 mt-1 uppercase tracking-widest">Enterprise Seafood Ops</p>
      </div>

      <nav className="flex-1 flex md:flex-col p-2 md:p-4 overflow-x-auto md:overflow-y-auto scrollbar-hide">
        {navItems.filter(item => item.roles.includes(role)).map((item) => {
          const isActive = location.pathname === item.path;
          return (
            <Link
              key={item.path}
              to={item.path}
              className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-all duration-200 whitespace-nowrap mb-0 md:mb-1 ${
                isActive ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white hover:bg-slate-800'
              }`}
            >
              <item.icon />
              <span className="font-medium">{item.label}</span>
            </Link>
          );
        })}
      </nav>

      <div className="p-4 border-t border-slate-800 hidden md:block">
        <div className="flex items-center gap-3 text-xs text-slate-500">
          <div className="w-2 h-2 rounded-full bg-green-500"></div>
          AGT Server Online
        </div>
      </div>
    </aside>
  );
};

export default App;

import React, { useState } from 'react';
import { Product, CartItem, UserRole } from '../types';
import { maskPII } from '../utils/masking';

interface POSViewProps {
  products: Product[];
  cart: CartItem[];
  addToCart: (p: Product, qty: number) => void;
  checkout: (nif?: string) => void;
  clearCart: () => void;
  role: UserRole;
}

const POSView: React.FC<POSViewProps> = ({ products, cart, addToCart, checkout, clearCart, role }) => {
  const [search, setSearch] = useState('');
  const [nif, setNif] = useState('');
  const [qtyInput, setQtyInput] = useState<{ [key: string]: string }>({});

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));
  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const tax = total * 0.14;

  const handleAdd = (p: Product) => {
    const qty = parseFloat(qtyInput[p.id] || '1');
    if (isNaN(qty) || qty <= 0) return;
    addToCart(p, qty);
    setQtyInput(prev => ({ ...prev, [p.id]: '' }));
  };

  return (
    <div className="flex flex-col lg:flex-row gap-6 h-[calc(100vh-10rem)]">
      {/* Product Grid Section */}
      <div className="flex-1 flex flex-col">
        <div className="mb-6 flex gap-4">
          <div className="relative flex-1">
            <input
              type="text"
              placeholder="Search products or scan barcode..."
              className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
            <div className="absolute left-3 top-3.5 text-slate-400">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-4 overflow-y-auto pr-2 custom-scrollbar">
          {filteredProducts.map(product => (
            <div key={product.id} className="bg-white rounded-xl border border-slate-200 p-4 hover:shadow-md transition-shadow cursor-pointer flex flex-col">
              <img src={product.image} className="h-32 w-full object-cover rounded-lg mb-3" alt={product.name} />
              <h3 className="font-semibold text-slate-800 line-clamp-1">{product.name}</h3>
              <p className="text-xs text-slate-500 mb-2">{product.category}</p>
              <div className="mt-auto">
                <p className="text-blue-700 font-bold mb-3">{product.price.toLocaleString()} Kz / {product.pricingType}</p>
                <div className="flex gap-2">
                  <input
                    type="number"
                    step={product.pricingType === 'kg' ? "0.1" : "1"}
                    placeholder={product.pricingType === 'kg' ? "0.0 kg" : "Qty"}
                    className="w-full text-xs border rounded px-2 py-1 outline-none focus:border-blue-500"
                    value={qtyInput[product.id] || ''}
                    onChange={(e) => setQtyInput(prev => ({ ...prev, [product.id]: e.target.value }))}
                  />
                  <button
                    onClick={() => handleAdd(product)}
                    className="bg-blue-600 text-white p-1.5 rounded hover:bg-blue-700 transition-colors"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className="w-full lg:w-96 bg-white rounded-2xl border border-slate-200 shadow-sm flex flex-col sticky top-8 h-full">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center">
          <h2 className="text-lg font-bold">Current Order</h2>
          <button onClick={clearCart} className="text-xs text-red-500 hover:underline">Clear</button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-2">
              <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><path d="M6 2 3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z"/><path d="M3 6h18"/><path d="M16 10a4 4 0 0 1-8 0"/></svg>
              <p>Empty cart</p>
            </div>
          ) : (
            cart.map((item, idx) => (
              <div key={idx} className="flex justify-between items-start border-b border-slate-50 pb-4">
                <div>
                  <h4 className="font-medium text-sm text-slate-800">{item.name}</h4>
                  <p className="text-xs text-slate-500">{item.quantity} x {item.price.toLocaleString()} Kz</p>
                </div>
                <p className="font-bold text-sm">{(item.quantity * item.price).toLocaleString()} Kz</p>
              </div>
            ))
          )}
        </div>

        <div className="p-6 bg-slate-50 rounded-b-2xl border-t border-slate-100 space-y-4">
          <div className="space-y-2 text-sm">
            <div className="flex justify-between">
              <span className="text-slate-500">Subtotal</span>
              <span className="font-medium">{total.toLocaleString()} Kz</span>
            </div>
            <div className="flex justify-between">
              <span className="text-slate-500">Tax (IVA 14%)</span>
              <span className="font-medium">{tax.toLocaleString()} Kz</span>
            </div>
            <div className="flex justify-between text-lg font-bold text-blue-900 border-t border-slate-200 pt-2">
              <span>Total</span>
              <span>{(total + tax).toLocaleString()} Kz</span>
            </div>
          </div>

          <div className="space-y-3">
            <input
              type="text"
              placeholder="Customer NIF (Optional)"
              className="w-full px-4 py-2 text-sm border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-blue-500"
              value={nif}
              onChange={(e) => setNif(e.target.value)}
            />
            <button
              disabled={cart.length === 0}
              onClick={() => checkout(nif)}
              className="w-full bg-blue-700 text-white font-bold py-3 rounded-xl hover:bg-blue-800 transition-all shadow-lg shadow-blue-200 disabled:opacity-50 disabled:shadow-none"
            >
              FINALIZE SALE
            </button>
            <p className="text-[10px] text-center text-slate-400">AGT Document Integrity Check Enabled</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default POSView;

import React, { useEffect, useState } from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar } from 'recharts';
import { Order, Product } from '../types';
import { getMarketInsights } from '../services/geminiService';

interface AdminDashboardProps {
  orders: Order[];
  products: Product[];
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ orders, products }) => {
  const [insights, setInsights] = useState<string>('Analyzing market data...');
  const [loadingInsights, setLoadingInsights] = useState(false);

  // Mock data for charts
  const chartData = [
    { name: 'Mon', sales: 420000 },
    { name: 'Tue', sales: 380000 },
    { name: 'Wed', sales: 510000 },
    { name: 'Thu', sales: 480000 },
    { name: 'Fri', sales: 620000 },
    { name: 'Sat', sales: 890000 },
    { name: 'Sun', sales: 310000 },
  ];

  const categoryData = [
    { name: 'Fresh Fish', value: 45 },
    { name: 'Shellfish', value: 30 },
    { name: 'Canned', value: 15 },
    { name: 'Others', value: 10 },
  ];

  useEffect(() => {
    const fetchInsights = async () => {
      setLoadingInsights(true);
