export enum UserRole {
  ADMIN = 'admin',
  STAFF = 'staff',
  CUSTOMER = 'customer'
}

export type PricingType = 'kg' | 'unit';

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  pricingType: PricingType;
  stock: number;
  image: string;
  description: string;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface UserProfile {
  id: string;
  fullName: string;
  email: string;
  phone: string;
  role: UserRole;
  nif?: string;
  address?: string;
}

export interface Order {
  id: string;
  customerId: string;
  customerName: string;
  items: CartItem[];
  total: number;
  tax: number;
  status: 'pending' | 'received' | 'ready' | 'delivered';
  type: 'pos' | 'online';
  createdAt: string;
  invoiceId?: string;
}

export interface Invoice {
  id: string;
  orderId: string;
  sequence: string; // e.g., FT 2024/0001
  nif: string;
  hash: string;
  taxStamp: string;
  createdAt: string;
}

export interface AppNotification {
  id: string;
  title: string;
  message: string;
  type: 'info' | 'warning' | 'error';
  isRead: boolean;
  createdAt: string;
}

export interface AppState {
  currentUser: UserProfile | null;
  products: Product[];
  orders: Order[];
  invoices: Invoice[];
  notifications: AppNotification[];
}

import React, { useState } from 'react';
import { HashRouter, Routes, Route, Navigate, Link, useLocation } from 'react-router-dom';
import { UserRole, UserProfile, Product, Order, Invoice, CartItem, AppNotification } from './types';
import { MOCK_PRODUCTS, ICONS } from './constants';
import POSView from './components/POSView';
import CatalogView from './components/CatalogView';
import AdminDashboard from './components/AdminDashboard';
import ProfileView from './components/ProfileView';
import OrderTracking from './components/OrderTracking';
import AGTReports from './components/AGTReports';
import OrderManagement from './components/OrderManagement';

const STOCK_THRESHOLD = 10;

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>({
    id: 'usr-1',
    fullName: 'Artur Gonçalves',
    email: 'artur@fishmarket.ao',
    phone: '923000111',
    role: UserRole.ADMIN,
    nif: '5401234567'
  });

  const [products, setProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [orders, setOrders] = useState<Order[]>([]);
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);

  const handleRoleChange = (role: UserRole) => {
    setCurrentUser(prev => prev ? { ...prev, role } : null);
  };

  const addToCart = (product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      return [...prev, { ...product, quantity }];
    });
  };

  const addNotification = (title: string, message: string, type: AppNotification['type']) => {
    const newNotif: AppNotification = {
      id: `NOT-${Date.now()}`,
      title,
      message,
      type,
      isRead: false,
      createdAt: new Date().toISOString()
    };
    setNotifications(prev => [newNotif, ...prev]);
  };

  const createOrder = (type: 'pos' | 'online', customNif?: string) => {
    if (cart.length === 0) return;

    // Check stock before finalization
    const outOfStockItems = cart.filter(item => {
      const p = products.find(prod => prod.id === item.id);
      return !p || p.stock < item.quantity;
    });

    if (outOfStockItems.length > 0) {
      alert(`Erro: Alguns itens ficaram sem stock: ${outOfStockItems.map(i => i.name).join(', ')}`);
      return;
    }

    const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const tax = total * 0.14;
    const orderId = `PED-${Date.now()}`;
    const invoiceId = `FT-${Date.now()}`;

    // Update Products Stock
    setProducts(prev => {
      return prev.map(p => {
        const cartItem = cart.find(ci => ci.id === p.id);
        if (cartItem) {
          const newStock = p.stock - cartItem.quantity;

          // Trigger Notification if stock falls below threshold
          if (newStock < STOCK_THRESHOLD) {
            addNotification(
              "Alerta de Stock Baixo",
              `O produto "${p.name}" atingiu o nível crítico: ${newStock.toFixed(1)} ${p.pricingType} restantes.`,
              "warning"
            );
          }
          return { ...p, stock: newStock };
        }
        return p;
      });
    });

    const newOrder: Order = {
      id: orderId,
      customerId: currentUser?.id || 'guest',
      customerName: currentUser?.fullName || 'Cliente Convidado',
      items: [...cart],
      total: total + tax,
      tax,
      status: 'received',
      type,
      createdAt: new Date().toISOString(),
      invoiceId
    };

    const newInvoice: Invoice = {
      id: invoiceId,
      orderId,
      sequence: `FT ${new Date().getFullYear()}/${(invoices.length + 1).toString().padStart(4, '0')}`,
      nif: customNif || currentUser?.nif || '999999999',
      hash: Math.random().toString(36).substring(7).toUpperCase(),
      taxStamp: 'AGT-CERT-2024-' + Math.random().toString(36).substring(4).toUpperCase(),
      createdAt: new Date().toISOString()
    };

    setOrders([newOrder, ...orders]);
    setInvoices([newInvoice, ...invoices]);
    setCart([]);
    alert(`Sucesso! Factura ${newInvoice.sequence} gerada.`);
  };

  const updateOrderStatus = (orderId: string, status: Order['status']) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status } : o));
  };

  const clearNotification = (id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  };

  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col md:flex-row bg-slate-50 text-slate-900">
        {/* Role Switcher Demo Tool */}
        <div className="fixed bottom-4 right-4 z-50 flex gap-2 bg-white/80 backdrop-blur-md p-2 rounded-full shadow-2xl border border-blue-100 items-center">
          <span className="text-[10px] font-black text-slate-400 px-2">DEBUG:</span>
          <button onClick={() => handleRoleChange(UserRole.ADMIN)} className={`px-3 py-1 rounded-full text-xs font-bold transition-all ${currentUser?.role === UserRole.ADMIN ? 'bg-blue-800 text-white scale-105 shadow-lg' : 'hover:bg-blue-50 text-slate-600'}`}>Admin</button>
          <button onClick={() => handleRoleChange(UserRole.STAFF)} className={`px-3 py-1 rounded-full text-xs font-bold transition-all ${currentUser?.role === UserRole.STAFF ? 'bg-blue-800 text-white scale-105 shadow-lg' : 'hover:bg-blue-50 text-slate-600'}`}>Funcionário</button>
          <button onClick={() => handleRoleChange(UserRole.CUSTOMER)} className={`px-3 py-1 rounded-full text-xs font-bold transition-all ${currentUser?.role === UserRole.CUSTOMER ? 'bg-blue-800 text-white scale-105 shadow-lg' : 'hover:bg-blue-50 text-slate-600'}`}>Cliente</button>
        </div>

        <Sidebar 
          role={currentUser?.role || UserRole.CUSTOMER} 
          user={currentUser} 
          notifications={notifications}
          onClearNotification={clearNotification}
        />

        <main className="flex-1 overflow-y-auto pb-20 md:pb-0">
          <div className="max-w-7xl mx-auto p-4 md:p-8">
            <Routes>
              {/* PÚBLICO / COMPARTILHADO */}
              <Route path="/profile" element={<ProfileView user={currentUser} onSave={(u) => setCurrentUser(u)} />} />

              {/* APENAS ADMIN */}
              {currentUser?.role === UserRole.ADMIN && (
                <>
                  <Route path="/dashboard" element={<AdminDashboard orders={orders} products={products} />} />
                  <Route path="/reports" element={<AGTReports invoices={invoices} orders={orders} />} />
                </>
              )}

              {/* ADMIN & FUNCIONÁRIO */}
              {(currentUser?.role === UserRole.ADMIN || currentUser?.role === UserRole.STAFF) && (
                <>
                  <Route path="/pos" element={<POSView products={products} cart={cart} addToCart={addToCart} checkout={(nif) => createOrder('pos', nif)} clearCart={() => setCart([])} role={currentUser.role} />} />
                  <Route path="/orders" element={<OrderManagement orders={orders} updateStatus={updateOrderStatus} role={currentUser.role} />} />
                </>
              )}

              {/* APENAS CLIENTE */}
              {currentUser?.role === UserRole.CUSTOMER && (
                <>
                  <Route path="/catalog" element={<CatalogView products={products} cart={cart} addToCart={addToCart} />} />
                  <Route path="/checkout" element={<OrderTracking cart={cart} createOrder={(nif) => createOrder('online', nif)} />} />
                  <Route path="/my-orders" element={<OrderManagement orders={orders.filter(o => o.customerId === currentUser.id)} updateStatus={() => {}} role={currentUser.role} />} />
                </>
              )}

              {/* REDIRECTS PADRÃO */}
              <Route path="*" element={
                <Navigate to={
                  currentUser?.role === UserRole.CUSTOMER ? "/catalog" : 
                  (currentUser?.role === UserRole.ADMIN ? "/dashboard" : "/pos")
                } replace />
              } />
            </Routes>
          </div>
        </main>
      </div>
    </HashRouter>
  );
};

