import { GoogleGenAI } from "@google/genai";

// Use process.env.API_KEY directly as per guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getMarketInsights = async (salesData: any) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `As a business analyst for a high-end fish market, analyze this sales data and provide 3 actionable insights for inventory and pricing strategy: ${JSON.stringify(salesData)}. Return response in Markdown.`,
      config: {
        systemInstruction: "You are a professional retail and seafood market consultant. Keep advice practical and concise.",
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Insight Error:", error);
    return "Unable to generate insights at this time.";
  }
};

import React, { useState } from 'react';
import { Product, CartItem, UserRole, BatchInfo } from '../types';
import { maskPII } from '../utils/masking';
import { PrimaveraAPI } from '../services/primaveraService';

interface POSViewProps {
  products: Product[];
  cart: CartItem[];
  addToCart: (p: Product, qty: number, batchId?: string) => void;
  checkout: (nif?: string, customerId?: string) => void;
  clearCart: () => void;
  role: UserRole;
}

const POSView: React.FC<POSViewProps> = ({ products, cart, addToCart, checkout, clearCart, role }) => {
  const [search, setSearch] = useState('');
  const [nif, setNif] = useState('');
  const [customerId, setCustomerId] = useState('usr-3'); // Mock de cliente selecionado
  const [qtyInput, setQtyInput] = useState<{ [key: string]: string }>({});
  const [batchSelection, setBatchSelection] = useState<{ [key: string]: string }>({});
  const [errorMessages, setErrorMessages] = useState<{ [key: string]: string }>({});

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));
  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const tax = total * 0.14;

  const handleAdd = (p: Product) => {
    const qty = parseFloat(qtyInput[p.id] || '1');
    const batchId = batchSelection[p.id];

    // Reset erro para este produto
    setErrorMessages(prev => ({ ...prev, [p.id]: '' }));

    if (isNaN(qty) || qty <= 0) {
      setErrorMessages(prev => ({ ...prev, [p.id]: "Qtd. inválida" }));
      return;
    }

    // Caso existam lotes configurados no produto
    if (p.batches && p.batches.length > 0) {
      if (!batchId) {
        setErrorMessages(prev => ({ ...prev, [p.id]: "Selecione um lote" }));
        return;
      }

      const selectedBatch = p.batches.find(b => b.id === batchId);
      if (selectedBatch && qty > selectedBatch.stockQuantity) {
        setErrorMessages(prev => ({ ...prev, [p.id]: `Excede lote (${selectedBatch.stockQuantity})` }));
        return;
      }
    } else {
      // Validação contra stock geral se não houver lotes
      if (qty > p.stock) {
        setErrorMessages(prev => ({ ...prev, [p.id]: `Stock insuficiente (${p.stock})` }));
        return;
      }
    }

    addToCart(p, qty, batchId);
    setQtyInput(prev => ({ ...prev, [p.id]: '' }));
    setBatchSelection(prev => ({ ...prev, [p.id]: '' }));
  };

  return (
    <div className="flex flex-col lg:flex-row gap-6 h-[calc(100vh-10rem)]">
      {/* Product Grid Section */}
      <div className="flex-1 flex flex-col">
        <div className="mb-6 flex gap-4">
          <div className="relative flex-1">
            <input
              type="text"
              placeholder="ERP Sync Active: Pesquisar produtos ou ler código..."
              className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
            <div className="absolute left-3 top-3.5 text-slate-400">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-4 overflow-y-auto pr-2 custom-scrollbar">
          {filteredProducts.map(product => (
            <div key={product.id} className={`bg-white rounded-xl border p-4 hover:shadow-md transition-all flex flex-col ${errorMessages[product.id] ? 'border-red-300 ring-1 ring-red-100' : 'border-slate-200'}`}>
              <img src={product.image} className="h-28 w-full object-cover rounded-lg mb-3" alt={product.name} />
              <h3 className="font-semibold text-slate-800 line-clamp-1">{product.name}</h3>

              {/* Seleção de Lote - Requisito Primavera V10 Logística */}
              <div className="mt-2 mb-3">
                <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Lote / Validade</p>
                <select 
                  className="w-full text-[10px] bg-slate-50 border rounded p-1 outline-none focus:border-blue-300"
                  value={batchSelection[product.id] || ''}
                  onChange={(e) => {
                    setBatchSelection(prev => ({ ...prev, [product.id]: e.target.value }));
                    setErrorMessages(prev => ({ ...prev, [product.id]: '' }));
                  }}
                >
                  <option value="">Selecionar Lote...</option>
                  {product.batches ? (
                    product.batches.map(batch => (
                      <option key={batch.id} value={batch.id}>
                        {batch.id} ({batch.stockQuantity} {product.pricingType}) - Val: {batch.expiryDate}
                      </option>
                    ))
                  ) : (
                    <>
                      <option value="L2026-A">L2026-A (Val: 12/26)</option>
                      <option value="L2026-B">L2026-B (Val: 01/27)</option>
                    </>
                  )}
                </select>
              </div>

              <div className="mt-auto">
                <div className="flex justify-between items-center mb-1">
                  <p className="text-blue-700 font-bold text-xs">{product.price.toLocaleString()} Kz / {product.pricingType}</p>
                  <p className="text-[9px] text-slate-400 font-bold">Disp: {product.stock}</p>
                </div>

                {errorMessages[product.id] && (
                  <p className="text-[9px] text-red-500 font-bold mb-1 animate-pulse">{errorMessages[product.id]}</p>
                )}

                <div className="flex gap-2">
                  <input
                    type="number"
                    placeholder="Qtd"
                    className={`w-full text-xs border rounded px-2 py-1 outline-none transition-colors ${errorMessages[product.id] ? 'border-red-400 bg-red-50' : 'focus:border-blue-400'}`}
                    value={qtyInput[product.id] || ''}
                    onChange={(e) => {
                      setQtyInput(prev => ({ ...prev, [product.id]: e.target.value }));
                      setErrorMessages(prev => ({ ...prev, [product.id]: '' }));
                    }}
                  />
                  <button
                    onClick={() => handleAdd(product)}
                    className="bg-blue-600 text-white p-1.5 rounded hover:bg-blue-700 transition-colors shrink-0"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className="w-full lg:w-96 bg-white rounded-2xl border border-slate-200 shadow-sm flex flex-col sticky top-8 h-full">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center">
          <div>
            <h2 className="text-lg font-bold text-slate-900">Venda Inteligente</h2>
            <p className="text-[10px] text-blue-500 font-bold">Primavera Integration Active</p>
          </div>
          <button onClick={clearCart} className="text-xs text-red-500 hover:underline">Limpar</button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-2 opacity-50">
              <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><path d="M6 2 3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z"/><path d="M3 6h18"/><path d="M16 10a4 4 0 0 1-8 0"/></svg>
              <p className="text-sm font-bold">Terminal Pronto</p>
            </div>
          ) : (
            cart.map((item, idx) => (
              <div key={idx} className="bg-slate-50 p-3 rounded-xl border border-slate-100 relative group">
                <div className="flex justify-between items-start">
                  <div>
                    <h4 className="font-bold text-sm text-slate-800">{item.name}</h4>
                    <p className="text-[10px] text-slate-400 font-bold">Lote: {item.selectedBatchId || 'N/A'}</p>
                    <p className="text-xs text-blue-600 mt-1">{item.quantity} x {item.price.toLocaleString()} Kz</p>
                  </div>
                  <p className="font-black text-sm">{(item.quantity * item.price).toLocaleString()} Kz</p>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="p-6 bg-slate-900 rounded-b-2xl border-t border-slate-800 space-y-4">
          <div className="space-y-2 text-sm text-white">
            <div className="flex justify-between opacity-70">
              <span>Subtotal (Logística)</span>
              <span>{total.toLocaleString()} Kz</span>
            </div>
            <div className="flex justify-between opacity-70">
              <span>IVA SVAT (14%)</span>
              <span>{tax.toLocaleString()} Kz</span>
            </div>
            <div className="flex justify-between text-lg font-black text-blue-400 border-t border-slate-800 pt-2">
              <span>Total Geral</span>
              <span>{(total + tax).toLocaleString()} Kz</span>
            </div>
          </div>

          <div className="space-y-3">
            <select 
              className="w-full bg-slate-800 border-slate-700 text-white p-2 rounded-lg text-xs outline-none focus:ring-1 focus:ring-blue-500"
              value={customerId}
              onChange={(e) => setCustomerId(e.target.value)}
            >
              <option value="guest">Consumidor Final</option>
              <option value="usr-3">João Luanda (Primavera Acc: 201)</option>
              <option value="usr-4">Bento Restaurante (Primavera Acc: 202)</option>
            </select>

            <button
              disabled={cart.length === 0}
              onClick={() => checkout(nif, customerId)}
              className="w-full bg-blue-600 text-white font-black py-4 rounded-xl hover:bg-blue-500 transition-all shadow-xl shadow-blue-900/40 disabled:opacity-50"
            >
              SINCRONIZAR E FINALIZAR
            </button>
            <div className="flex justify-center items-center gap-2">
               <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
               <p className="text-[8px] uppercase tracking-tighter text-slate-500 font-black">Primavera Web API Gateway Online</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default POSView;

