  const [errorMessages, setErrorMessages] = useState<{ [key: string]: string }>({});

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));
  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const tax = total * 0.14;

  // Validação proativa ao alterar inputs
  const validateInput = (p: Product, qtyStr: string, batchId: string) => {
    const qty = parseFloat(qtyStr);
    let error = "";

    if (qtyStr !== "" && (isNaN(qty) || qty <= 0)) {
      error = "Qtd. inválida";
    } else if (qtyStr !== "") {
      if (p.batches && p.batches.length > 0) {
        if (!batchId) {
          error = "Selecione um lote";
        } else {
          const selectedBatch = p.batches.find(b => b.id === batchId);
          if (selectedBatch && qty > selectedBatch.stockQuantity) {
            error = `Max: ${selectedBatch.stockQuantity} no lote`;
          }
        }
      } else if (qty > p.stock) {
        error = `Stock max: ${p.stock}`;
      }
    }

    setErrorMessages(prev => ({ ...prev, [p.id]: error }));
  };

  const handleQtyChange = (p: Product, value: string) => {
    setQtyInput(prev => ({ ...prev, [p.id]: value }));
    validateInput(p, value, batchSelection[p.id] || '');
  };

  const handleBatchChange = (p: Product, value: string) => {
    setBatchSelection(prev => ({ ...prev, [p.id]: value }));
    validateInput(p, qtyInput[p.id] || '', value);
  };

  const handleAdd = (p: Product) => {
    const qty = parseFloat(qtyInput[p.id] || '1');
    const batchId = batchSelection[p.id];

    // Validação final antes de adicionar
    if (isNaN(qty) || qty <= 0) return;
    if (p.batches && p.batches.length > 0 && !batchId) return;
    if (errorMessages[p.id]) return;

    addToCart(p, qty, batchId);

    // Limpar apenas se foi bem sucedido
    setQtyInput(prev => ({ ...prev, [p.id]: '' }));
    setBatchSelection(prev => ({ ...prev, [p.id]: '' }));
    setErrorMessages(prev => ({ ...prev, [p.id]: '' }));
  };

  const getAvailableStock = (p: Product) => {
    const selectedBatchId = batchSelection[p.id];
    if (p.batches && selectedBatchId) {
      const batch = p.batches.find(b => b.id === selectedBatchId);
      return batch ? batch.stockQuantity : 0;
    }
    return p.stock;
  };

  return (
    <div className="flex flex-col lg:flex-row gap-6 h-[calc(100vh-10rem)]">
      <div className="flex-1 flex flex-col">
        <div className="mb-6 flex gap-4">
          <div className="relative flex-1">
            <input
              type="text"
              placeholder="Pesquisar produtos (V10 Sync Active)..."
              className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
            <div className="absolute left-3 top-3.5 text-slate-400">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-4 overflow-y-auto pr-2 custom-scrollbar">
          {filteredProducts.map(product => {
            const dispStock = getAvailableStock(product);
            const hasError = !!errorMessages[product.id];

            return (
              <div key={product.id} className={`bg-white rounded-xl border p-4 hover:shadow-md transition-all flex flex-col ${hasError ? 'border-red-300 ring-1 ring-red-100 bg-red-50/10' : 'border-slate-200'}`}>
                <img src={product.image} className="h-28 w-full object-cover rounded-lg mb-3" alt={product.name} />
                <h3 className="font-semibold text-slate-800 line-clamp-1">{product.name}</h3>

                <div className="mt-2 mb-3">
                  <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Rastreabilidade (Lote)</p>
                  <select 
                    className={`w-full text-[10px] bg-slate-50 border rounded p-1 outline-none transition-colors ${hasError && !batchSelection[product.id] ? 'border-red-400' : 'focus:border-blue-300'}`}
                    value={batchSelection[product.id] || ''}
                    onChange={(e) => handleBatchChange(product, e.target.value)}
                  >
                    <option value="">-- Seleccionar --</option>
                    {product.batches?.map(batch => (
                      <option key={batch.id} value={batch.id}>
                        {batch.id} ({batch.stockQuantity} {product.pricingType})
                      </option>
                    ))}
                    {!product.batches && (
                      <option value="STD">Lote Padrão (FIFO)</option>
                    )}
                  </select>
                </div>

                <div className="mt-auto">
                  <div className="flex justify-between items-center mb-1">
                    <p className="text-blue-700 font-bold text-xs">{product.price.toLocaleString()} Kz / {product.pricingType}</p>
                    <p className={`text-[9px] font-bold ${dispStock <= 5 ? 'text-red-500' : 'text-slate-400'}`}>
                      Disp: {dispStock}
                    </p>
                  </div>

                  {hasError && (
                    <p className="text-[9px] text-red-500 font-bold mb-1 animate-pulse">{errorMessages[product.id]}</p>
                  )}

                  <div className="flex gap-2">
                    <input
                      type="number"
                      placeholder="Qtd"
                      className={`w-full text-xs border rounded px-2 py-1 outline-none transition-colors ${hasError ? 'border-red-400 bg-red-50' : 'focus:border-blue-400'}`}
                      value={qtyInput[product.id] || ''}
                      onChange={(e) => handleQtyChange(product, e.target.value)}
                    />
                    <button
                      onClick={() => handleAdd(product)}
                      disabled={hasError || !qtyInput[product.id]}
                      className={`p-1.5 rounded transition-colors shrink-0 ${hasError || !qtyInput[product.id] ? 'bg-slate-200 text-slate-400 cursor-not-allowed' : 'bg-blue-600 text-white hover:bg-blue-700'}`}
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
                    </button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <div className="w-full lg:w-96 bg-white rounded-2xl border border-slate-200 shadow-sm flex flex-col sticky top-8 h-full">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center">
          <div>
            <h2 className="text-lg font-bold text-slate-900">Checkout Mobile</h2>
            <p className="text-[10px] text-blue-500 font-bold">Primavera Logística V10</p>
          </div>
          <button onClick={clearCart} className="text-xs text-red-500 hover:underline font-bold">Limpar</button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-2 opacity-50">
              <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><path d="M6 2 3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z"/><path d="M3 6h18"/><path d="M16 10a4 4 0 0 1-8 0"/></svg>
              <p className="text-sm font-bold tracking-tight">Cesto Vazio</p>
            </div>
          ) : (
            cart.map((item, idx) => (
              <div key={idx} className="bg-slate-50 p-3 rounded-xl border border-slate-100 relative group animate-in slide-in-from-right-2 duration-200">
                <div className="flex justify-between items-start">
                  <div>
                    <h4 className="font-bold text-sm text-slate-800">{item.name}</h4>
                    <p className="text-[10px] text-slate-400 font-bold uppercase">Lote: {item.selectedBatchId || 'STD'}</p>
                    <p className="text-xs text-blue-600 mt-1">{item.quantity} x {item.price.toLocaleString()} Kz</p>
                  </div>
                  <p className="font-black text-sm">{(item.quantity * item.price).toLocaleString()} Kz</p>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="p-6 bg-slate-900 rounded-b-2xl border-t border-slate-800 space-y-4">
          <div className="space-y-2 text-sm text-white">
            <div className="flex justify-between opacity-70 font-medium">
              <span>Subtotal</span>
              <span>{total.toLocaleString()} Kz</span>
            </div>
            <div className="flex justify-between opacity-70 font-medium">
              <span>IVA SVAT (14%)</span>
              <span>{tax.toLocaleString()} Kz</span>
            </div>
            <div className="flex justify-between text-lg font-black text-blue-400 border-t border-slate-800 pt-3">
              <span>Total Final</span>
              <span>{(total + tax).toLocaleString()} Kz</span>
            </div>
          </div>

          <div className="space-y-3">
            <label className="text-[10px] text-slate-500 font-black uppercase">Conta Corrente (Financeiro)</label>
            <select 
              className="w-full bg-slate-800 border-slate-700 text-white p-2.5 rounded-lg text-xs outline-none focus:ring-1 focus:ring-blue-500"
              value={customerId}
              onChange={(e) => setCustomerId(e.target.value)}
            >
              <option value="guest">Consumidor Final (N/A)</option>
              <option value="usr-3">João Luanda (21.1.001)</option>
              <option value="usr-4">Bento Restaurante (21.1.002)</option>
            </select>

            <button
              disabled={cart.length === 0}
              onClick={() => checkout(nif, customerId)}
              className="w-full bg-blue-600 text-white font-black py-4 rounded-xl hover:bg-blue-500 transition-all shadow-xl shadow-blue-900/40 disabled:opacity-30 disabled:cursor-not-allowed"
            >
              SINCRONIZAR ERP
            </button>
            <div className="flex justify-center items-center gap-2">
               <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
               <p className="text-[8px] uppercase tracking-tighter text-slate-500 font-black">Conectado a Web API Primavera</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

