import React, { useState } from 'react';
import { Product, CartItem, UserRole } from '../types';

interface POSViewProps {
  products: Product[];
  cart: CartItem[];
  addToCart: (p: Product, qty: number, batchId?: string) => void;
  checkout: (nif?: string, customerId?: string) => void;
  clearCart: () => void;
  role: UserRole;
}

const POSView: React.FC<POSViewProps> = ({ products, cart, addToCart, checkout, clearCart, role }) => {
  const [search, setSearch] = useState('');
  const [customerId, setCustomerId] = useState('usr-3');
  const [qtyInput, setQtyInput] = useState<{ [key: string]: string }>({});
  const [batchSelection, setBatchSelection] = useState<{ [key: string]: string }>({});
  const [errorMessages, setErrorMessages] = useState<{ [key: string]: string }>({});

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));
  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const tax = total * 0.14;

  /**
   * Validação centralizada para garantir integridade antes de permitir a adição ao carrinho.
   */
  const validateInput = (p: Product, qtyStr: string, batchId: string) => {
    const qty = parseFloat(qtyStr);
    let error = "";

    if (qtyStr === "") {
      error = ""; // Campo vazio não mostra erro até tentar adicionar ou se já houver interação
    } else if (isNaN(qty) || qty <= 0) {
      error = "Quantidade deve ser superior a 0";
    } else {
      if (p.batches && p.batches.length > 0) {
        if (!batchId) {
          error = "Selecione um lote válido";
        } else {
          const selectedBatch = p.batches.find(b => b.id === batchId);
          if (selectedBatch && qty > selectedBatch.stockQuantity) {
            error = `Stock insuficiente no lote (Máx: ${selectedBatch.stockQuantity})`;
          }
        }
      } else if (qty > p.stock) {
        error = `Excede stock total disponível (Máx: ${p.stock})`;
      }
    }

    setErrorMessages(prev => ({ ...prev, [p.id]: error }));
    return error === "";
  };

  const handleQtyChange = (p: Product, value: string) => {
    setQtyInput(prev => ({ ...prev, [p.id]: value }));
    validateInput(p, value, batchSelection[p.id] || '');
  };

  const handleBatchChange = (p: Product, value: string) => {
    setBatchSelection(prev => ({ ...prev, [p.id]: value }));
    validateInput(p, qtyInput[p.id] || '', value);
  };

  const handleAdd = (p: Product) => {
    const qtyStr = qtyInput[p.id] || '';
    const batchId = batchSelection[p.id];

    // Forçar validação ao clicar se estiver vazio
    if (qtyStr === "") {
        setErrorMessages(prev => ({ ...prev, [p.id]: "Introduza a quantidade" }));
        return;
    }

    if (validateInput(p, qtyStr, batchId || '')) {
      addToCart(p, parseFloat(qtyStr), batchId);
      setQtyInput(prev => ({ ...prev, [p.id]: '' }));
      setBatchSelection(prev => ({ ...prev, [p.id]: '' }));
      setErrorMessages(prev => ({ ...prev, [p.id]: '' }));
    }
  };

  const getAvailableStockDisplay = (p: Product) => {
    const selectedBatchId = batchSelection[p.id];
    if (p.batches && selectedBatchId) {
      const batch = p.batches.find(b => b.id === selectedBatchId);
      return batch ? batch.stockQuantity : 0;
    }
    return p.stock;
  };

  return (
    <div className="flex flex-col lg:flex-row gap-6 h-[calc(100vh-10rem)]">
      {/* Zona de Catálogo POS */}
      <div className="flex-1 flex flex-col">
        <div className="mb-6">
          <div className="relative">
            <input
              type="text"
              placeholder="Pesquisar peixe ou marisco (V10 Online)..."
              className="w-full pl-10 pr-4 py-4 rounded-2xl border border-slate-200 focus:ring-4 focus:ring-blue-100 outline-none transition-all shadow-sm"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
            <div className="absolute left-3.5 top-4.5 text-slate-400">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-5 overflow-y-auto pr-2 custom-scrollbar">
          {filteredProducts.map(product => {
            const dispStock = getAvailableStockDisplay(product);
            const error = errorMessages[product.id];
            const hasError = !!error;
            const needsBatch = product.batches && product.batches.length > 0;

            return (
              <div key={product.id} className={`bg-white rounded-2xl border-2 p-5 transition-all flex flex-col relative ${hasError ? 'border-red-500 shadow-lg shadow-red-50' : 'border-slate-100 hover:border-blue-200 shadow-sm'}`}>
                <div className="relative mb-4">
                  <img src={product.image} className="h-40 w-full object-cover rounded-xl" alt={product.name} />
                  {needsBatch && (
                    <div className="absolute top-2 right-2 bg-blue-600 text-white text-[8px] font-black px-2 py-1 rounded-full uppercase tracking-widest">
                      Lote Obrigatório
                    </div>
                  )}
                </div>

                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-bold text-slate-900 leading-tight">{product.name}</h3>
                  <span className={`text-[10px] font-bold px-2 py-0.5 rounded ${dispStock > 0 ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>
                    Stock: {dispStock}
                  </span>
                </div>

                <div className="space-y-4 mt-auto">
                  {/* Seleção de Lote */}
                  <div>
                    <label className="text-[9px] font-black text-slate-400 uppercase block mb-1">Rastreabilidade / Lote</label>
                    <select 
                      className={`w-full text-xs bg-slate-50 border rounded-lg p-2 outline-none transition-all ${hasError && error.includes("lote") ? 'border-red-500 ring-2 ring-red-100' : 'border-slate-200 focus:border-blue-500'}`}
                      value={batchSelection[product.id] || ''}
                      onChange={(e) => handleBatchChange(product, e.target.value)}
                    >
                      <option value="">-- Seleccionar Lote --</option>
                      {product.batches?.map(batch => (
                        <option key={batch.id} value={batch.id}>
                          {batch.id} (Disponível: {batch.stockQuantity} {product.pricingType})
                        </option>
                      ))}
                      {!product.batches && <option value="FIFO">Standard FIFO</option>}
                    </select>
                  </div>

                  {/* Input de Quantidade e Preço */}
                  <div className="flex items-end gap-3">
                    <div className="flex-1">
                      <label className="text-[9px] font-black text-slate-400 uppercase block mb-1">Qtd. ({product.pricingType})</label>
                      <input
                        type="number"
                        step="0.1"
                        placeholder="0.00"
                        className={`w-full text-sm font-bold border rounded-lg px-3 py-2 outline-none transition-all ${hasError && !error.includes("lote") ? 'border-red-500 ring-2 ring-red-100 bg-red-50' : 'border-slate-200 focus:border-blue-500'}`}
                        value={qtyInput[product.id] || ''}
                        onChange={(e) => handleQtyChange(product, e.target.value)}
                      />
                    </div>
                    <div className="text-right">
                       <p className="text-[9px] font-black text-slate-400 uppercase">Preço Unit.</p>
                       <p className="text-blue-700 font-black text-sm">{product.price.toLocaleString()} Kz</p>
                    </div>
                  </div>

                  {/* Mensagem de Erro Proeminente */}
                  {hasError && (
                    <div className="bg-red-50 text-red-600 p-2 rounded-lg border border-red-100 flex items-center gap-2 animate-in fade-in slide-in-from-top-1">
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" x2="12" y1="8" y2="12"/><line x1="12" x2="12.01" y1="16" y2="16"/></svg>
                      <span className="text-[10px] font-bold leading-tight">{error}</span>
                    </div>
                  )}

                  <button
                    onClick={() => handleAdd(product)}
                    disabled={hasError || !qtyInput[product.id]}
                    className={`w-full py-3 rounded-xl font-black text-xs uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${hasError || !qtyInput[product.id] ? 'bg-slate-100 text-slate-400 cursor-not-allowed border border-slate-200' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-md active:scale-95'}`}
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
                    Adicionar ao Cesto
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Painel de Checkout Lateral */}
      <div className="w-full lg:w-96 bg-white rounded-3xl border border-slate-200 shadow-xl flex flex-col h-full overflow-hidden">
        <div className="p-6 border-b border-slate-100 bg-slate-50/50">
