                <option value="usr-3">João Luanda (Conta: 21.1.001)</option>
                <option value="usr-4">Bento Restaurante (Conta: 21.1.002)</option>
              </select>
            </div>

            <button
              disabled={cart.length === 0}
              onClick={() => checkout('', customerId)}
              className="w-full bg-blue-500 text-white font-black py-5 rounded-2xl hover:bg-blue-400 transition-all shadow-lg shadow-blue-500/20 disabled:opacity-20 disabled:cursor-not-allowed text-sm uppercase tracking-widest active:scale-95"
